(()=>{document.addEventListener("DOMContentLoaded",()=>{function r(e){let t=e.closest(".user-menu-wrap");if(!t)return null;let s=t.querySelector('[aria-haspopup="menu"]'),n=t.querySelector(".user-menu");return s&&n?{trigger:s,menu:n}:null}function i(e){e.menu.classList.add("is-open"),e.trigger.setAttribute("aria-expanded","true")}function o(e){e.menu.classList.remove("is-open"),e.trigger.setAttribute("aria-expanded","false")}function u(){document.querySelectorAll(".user-menu.is-open").forEach(e=>{let t=r(e);t&&o(t)})}window.closeUserMenu=u,document.addEventListener("click",e=>{let t=e.target.closest('[aria-haspopup="menu"][aria-controls]');if(t){let n=r(t);if(n){e.stopPropagation(),n.menu.classList.contains("is-open")?o(n):i(n);return}}let s=e.target.closest(".user-menu.is-open");if(s){let n=r(s);n&&o(n);return}u()})});})();
